+import { BatchSelectRecentItemView } from './BatchSelectRecentItemView'; // Assuming BatchSelectRecentItemView is in a separate file
+
+// Define a reusable component for the content of each recent contact list item.
+// This extracts the complex UI logic from the LazyForEach, improving performance
+// and maintainability as suggested by the linting rule.
+@Reusable
+@Component
+struct RecentListItemContent {
+  // The item data from the LazyForEach, containing calllog details, index, and divider visibility.
+  @State item: { calllog: any, index: number, showDivifer: boolean } = { calllog: {}, index: 0, showDivifer: false };
+  // Callback function to handle item clicks, passed from the parent component.
+  @State onRecentItemClicked: (index: number) => void = (index) => {};
+
+  // Lifecycle hook called when the component is reused.
+  // It updates the @State properties with new data from the params.
+  aboutToReuse(params: Record<string, ESObject>) {
+    this.item = params.item as { calllog: any, index: number, showDivifer: boolean };
+    this.onRecentItemClicked = params.onRecentItemClicked as (index: number) => void;
+  }
+
+  build() {
+    Stack({ alignContent: Alignment.BottomEnd }) {
+      // The existing BatchSelectRecentItemView component.
+      BatchSelectRecentItemView({
+        item: this.item.calllog,
+        index: this.item.index,
+        onRecentItemClicked: (index) => this.onRecentItemClicked(index)
+      })
+
+      // Conditional Divider based on item's showDivifer property.
+      if (this.item.showDivifer) {
+        Divider()
+          .color($r("sys.color.ohos_id_color_list_separator"))
+          .margin({ left: 76, right: $r("app.float.id_card_margin_max") })
+      }
+    }
+  }
+}

