+
+@Reusable
+@Component
+struct LottieItemComponent {
+  @State animationPath: string = ''
+  @State animationController: LottieController = new LottieController()
+
+  // Helper to get file name
+  getFileName(path: string): string {
+    return path.split('/').pop()?.replace('.json', '') || ''
+  }
+
+  aboutToReuse(params: Record<string, ESObject>) {
+    if (params.animationPath !== undefined) {
+      this.animationPath = params.animationPath as string
+    }
+    if (params.animationController !== undefined) {
+      this.animationController = params.animationController as LottieController
+    }
+  }
+
+  build() {
+    Column() {
+      LottieView({
+        loop: true,
+        autoplay: true,
+        autoSkip: true,
+        path: $rawfile(this.animationPath),
+        controller: this.animationController,
+      })
+        .width('60%')
+        .height('30%')
+        .aspectRatio(1)
+        .backgroundColor('#F1F3F5')
+        .margin(10)
+        .onClick(() => {
+          this.animationController.play()
+        })
+      Text(this.getFileName(this.animationPath))
+        .fontSize(14)
+        .margin({ top: 5, bottom: 5 })
+        .textAlign(TextAlign.Center)
+        .maxLines(2)
+        .textOverflow({ overflow: TextOverflow.Ellipsis })
+    }
+  }
+}

